import { useEffect, useRef, useCallback, useState } from "react";
 
const LOGO_SRC = "data:image/png;base64,";
 
export default function MagneticLogoDemo() {
  const [radius, setRadius] = useState(130);
  const [force, setForce] = useState(7);
  const [damping, setDamping] = useState(0.9);
  const [spring, setSpring] = useState(0.08);
 
  return (
    <div className="min-h-screen w-full bg-[#0a0a0a] flex flex-col items-center justify-center gap-8 px-6 py-10">
      <MagneticLogo
        src={LOGO_SRC}
        width={640}
        height={433}
        radius={radius}
        force={force}
        damping={damping}
        spring={spring}
        gap={2}
        className="mx-auto"
      />
      <p className="text-neutral-500 text-sm tracking-wide">
        Move your cursor over the mark.
      </p>
 
      <div className="w-full max-w-md grid grid-cols-2 gap-x-6 gap-y-4 text-neutral-300 text-xs">
        <label className="flex flex-col gap-1">
          <span>Radius: {radius}px</span>
          <input type="range" min="40" max="250" value={radius}
            onChange={(e) => setRadius(Number(e.target.value))} />
        </label>
        <label className="flex flex-col gap-1">
          <span>Force: {force}</span>
          <input type="range" min="1" max="15" step="0.5" value={force}
            onChange={(e) => setForce(Number(e.target.value))} />
        </label>
        <label className="flex flex-col gap-1">
          <span>Damping: {damping}</span>
          <input type="range" min="0.8" max="0.98" step="0.01" value={damping}
            onChange={(e) => setDamping(Number(e.target.value))} />
        </label>
        <label className="flex flex-col gap-1">
          <span>Spring: {spring}</span>
          <input type="range" min="0.02" max="0.2" step="0.01" value={spring}
            onChange={(e) => setSpring(Number(e.target.value))} />
        </label>
      </div>
    </div>
  );
}
 
function MagneticLogo({
  src,
  width = 640,
  height = 420,
  radius = 120,
  force = 6,
  damping = 0.9,
  spring = 0.08,
  gap = 4,
  className = "",
  ariaLabel = "Rayhan Digital Hub logo",
}) {
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const particlesRef = useRef([]);
  const mouseRef = useRef({ x: -9999, y: -9999, active: false });
  const rafRef = useRef(null);
  const dprRef = useRef(1);
  const reducedMotionRef = useRef(false);
 
  const buildParticles = useCallback(
    (img, cssW, cssH) => {
      const off = document.createElement("canvas");
      off.width = cssW;
      off.height = cssH;
      const octx = off.getContext("2d", { willReadFrequently: true });
      octx.clearRect(0, 0, cssW, cssH);
 
      const scale = Math.min(cssW / img.width, cssH / img.height);
      const drawW = img.width * scale;
      const drawH = img.height * scale;
      const offsetX = (cssW - drawW) / 2;
      const offsetY = (cssH - drawH) / 2;
      octx.drawImage(img, offsetX, offsetY, drawW, drawH);
 
      const { data } = octx.getImageData(0, 0, cssW, cssH);
      const particles = [];
 
      for (let y = 0; y < cssH; y += gap) {
        for (let x = 0; x < cssW; x += gap) {
          const idx = (y * cssW + x) * 4;
          const alpha = data[idx + 3];
          if (alpha > 80) {
            const r = data[idx];
            const g = data[idx + 1];
            const b = data[idx + 2];
            particles.push({
              ox: x,
              oy: y,
              x,
              y,
              vx: 0,
              vy: 0,
              color: `rgba(${r},${g},${b},${alpha / 255})`,
            });
          }
        }
      }
      return particles;
    },
    [gap]
  );
 
  useEffect(() => {
    reducedMotionRef.current =
      typeof window !== "undefined" &&
      window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  }, []);
 
  useEffect(() => {
    let disposed = false;
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;
 
    const ctx = canvas.getContext("2d");
    let resizeTimeout;
 
    const setup = () => {
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      dprRef.current = dpr;
 
      const rect = container.getBoundingClientRect();
      const cssW = Math.max(1, Math.round(rect.width));
      const cssH = Math.max(1, Math.round(rect.height));
 
      canvas.width = cssW * dpr;
      canvas.height = cssH * dpr;
      canvas.style.width = `${cssW}px`;
      canvas.style.height = `${cssH}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
 
      const img = new Image();
      img.decoding = "async";
      img.onload = () => {
        if (disposed) return;
        particlesRef.current = buildParticles(img, cssW, cssH);
      };
      img.src = src;
    };
 
    setup();
 
    const handleResize = () => {
      clearTimeout(resizeTimeout);
      resizeTimeout = setTimeout(setup, 150);
    };
    window.addEventListener("resize", handleResize);
 
    const setMouseFromEvent = (clientX, clientY) => {
      const rect = canvas.getBoundingClientRect();
      mouseRef.current.x = clientX - rect.left;
      mouseRef.current.y = clientY - rect.top;
      mouseRef.current.active = true;
    };
    const handleMouseMove = (e) => setMouseFromEvent(e.clientX, e.clientY);
    const handleTouchMove = (e) => {
      if (!e.touches || !e.touches[0]) return;
      setMouseFromEvent(e.touches[0].clientX, e.touches[0].clientY);
    };
    const handleLeave = () => {
      mouseRef.current.active = false;
      mouseRef.current.x = -9999;
      mouseRef.current.y = -9999;
    };
 
    canvas.addEventListener("mousemove", handleMouseMove);
    canvas.addEventListener("mouseleave", handleLeave);
    canvas.addEventListener("touchmove", handleTouchMove, { passive: true });
    canvas.addEventListener("touchend", handleLeave);
    canvas.addEventListener("touchcancel", handleLeave);
 
    const particleSize = Math.max(1, gap * 0.9);
 
    const render = () => {
      const w = canvas.width / dprRef.current;
      const h = canvas.height / dprRef.current;
      ctx.clearRect(0, 0, w, h);
 
      const { x: mx, y: my, active } = mouseRef.current;
      const particles = particlesRef.current;
      const reduced = reducedMotionRef.current;
 
      for (let i = 0; i < particles.length; i++) {
        const p = particles[i];
 
        if (!reduced && active) {
          const dx = p.x - mx;
          const dy = p.y - my;
          const dist = Math.sqrt(dx * dx + dy * dy) || 0.0001;
          if (dist < radius) {
            const falloff = (radius - dist) / radius;
            const strength = falloff * falloff * force;
            p.vx += (dx / dist) * strength;
            p.vy += (dy / dist) * strength;
          }
        }
 
        p.vx += (p.ox - p.x) * spring;
        p.vy += (p.oy - p.y) * spring;
 
        p.vx *= damping;
        p.vy *= damping;
 
        p.x += p.vx;
        p.y += p.vy;
 
        ctx.fillStyle = p.color;
        ctx.fillRect(p.x, p.y, particleSize, particleSize);
      }
 
      rafRef.current = requestAnimationFrame(render);
    };
 
    rafRef.current = requestAnimationFrame(render);
 
    return () => {
      disposed = true;
      cancelAnimationFrame(rafRef.current);
      clearTimeout(resizeTimeout);
      window.removeEventListener("resize", handleResize);
      canvas.removeEventListener("mousemove", handleMouseMove);
      canvas.removeEventListener("mouseleave", handleLeave);
      canvas.removeEventListener("touchmove", handleTouchMove);
      canvas.removeEventListener("touchend", handleLeave);
      canvas.removeEventListener("touchcancel", handleLeave);
    };
  }, [src, radius, force, damping, spring, gap, buildParticles]);
 
  return (
    <div
      ref={containerRef}
      role="img"
      aria-label={ariaLabel}
      className={`relative w-full ${className}`}
      style={{ aspectRatio: `${width} / ${height}`, maxWidth: width }}
    >
      <canvas
        ref={canvasRef}
        className="block h-full w-full select-none"
        aria-hidden="true"
      />
      <img src={src} alt={ariaLabel} className="sr-only" />
    </div>
  );
}
 
